(1878, 20, '药品均匀度不合格', '药品均匀度不合格隐患排查', '重大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1879, 20, '药品检验标准品失效', '药品检验标准品失效隐患排查', '较大', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
(1880, 20, '药品生产偏差未及时处理', '药品生产偏差未及时处理隐患排查', '一般', '《中华人民共和国安全生产法》', '第九十九条', '生产经营单位有下列行为之一的，责令限期改正，处五万元以下的罚款：（一）未在有较大危险因素的生产经营场所和有关设施、设备上设置明显的安全警示标志的；（二）安全设备的安装、使用、检测、改造和报废不符合国家标准或者行业标准的；（三）未对安全设备进行经常性维护、保养和定期检测的。'),
(1881, 20, '药品生产变更未按规定申报', '药品生产变更未按规定申报隐患排查', '重大', '《中华人民共和国安全生产法》', '第三条', '安全生产工作应当以人为本，坚持人民至上、生命至上，把保护人民生命安全摆在首位，树牢安全发展理念，坚持安全第一、预防为主、综合治理的方针，从源头上防范化解重大安全风险。'),
(1882, 20, '药品生产批次管理混乱', '药品生产批次管理混乱隐患排查', '较大', '《中华人民共和国安全生产法》', '第二十一条', '生产经营单位的主要负责人对本单位安全生产工作负有下列职责：（一）建立健全并落实本单位全员安全生产责任制，加强安全生产标准化建设；（二）组织制定并实施本单位安全生产规章制度和操作规程；（三）组织制定并实施本单位安全生产教育和培训计划；（四）保证本单位安全生产投入的有效实施；（五）组织建立并落实安全风险分级管控和隐患排查治理双重预防工作机制，督促、检查本单位的安全生产工作，及时消除生产安全事故隐患；（六）组织制定并实施本单位的生产安全事故应急救援预案；（七）及时、如实报告生产安全事故。'),
(1883, 20, '药品生产批记录填写不完整', '药品生产批记录填写不完整隐患排查', '一般', '《中华人民共和国安全生产法》', '第二十二条', '生产经营单位的全员安全生产责任制应当明确各岗位的责任人员、责任范围和考核标准等内容。生产经营单位应当建立相应的机制，加强对全员安全生产责任制落实情况的监督考核，保证全员安全生产责任制的落实。'),
(1884, 20, '药品生产清场不彻底', '药品生产清场不彻底隐患排查', '重大', '《中华人民共和国安全生产法》', '第二十八条', '生产经营单位应当对从业人员进行安全生产教育和培训，保证从业人员具备必要的安全生产知识，熟悉有关的安全生产规章制度和安全操作规程，掌握本岗位的安全操作技能，了解事故应急处理措施，知悉自身在安全生产方面的权利和义务。未经安全生产教育和培训合格的从业人员，不得上岗作业。'),
(1885, 20, '药品生产交叉污染', '药品生产交叉污染隐患排查', '较大', '《中华人民共和国安全生产法》', '第三十六条', '安全设备的设计、制造、安装、使用、检测、维修、改造和报废，应当符合国家标准或者行业标准。生产经营单位必须对安全设备进行经常性维护、保养，并定期检测，保证正常运转。维护、保养、检测应当作好记录，并由有关人员签字。'),
(1886, 20, '药品生产环境污染', '药品生产环境污染隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全并落实生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。事故隐患排查治理情况应当如实记录，并通过职工大会或者职工代表大会、信息公示栏等方式向从业人员通报。'),
(1887, 20, '药品生产无菌操作违规', '药品生产无菌操作违规隐患排查', '重大', '《中华人民共和国安全生产法》', '第四十四条', '生产经营单位应当教育和督促从业人员严格执行本单位的安全生产规章制度和安全操作规程；并向从业人员如实告知作业场所和工作岗位存在的危险因素、防范措施以及事故应急措施。'),
(1888, 20, '药品生产设备清洁验证不充分', '药品生产设备清洁验证不充分隐患排查', '较大', '《中华人民共和国安全生产法》', '第四十五条', '生产经营单位必须为从业人员提供符合国家标准或者行业标准的劳动防护用品，并监督、教育从业人员按照使用规则佩戴、使用。'),
(1889, 20, '药品生产空调净化系统故障', '药品生产空调净化系统故障隐患排查', '一般', '《中华人民共和国安全生产法》', '第四十六条', '生产经营单位的安全生产管理人员应当根据本单位的生产经营特点，对安全生产状况进行经常性检查；对检查中发现的安全问题，应当立即处理；不能处理的，应当及时报告本单位有关负责人，有关负责人应当及时处理。检查及处理情况应当如实记录在案。'),
(1890, 20, '药品生产纯化水系统故障', '药品生产纯化水系统故障隐患排查', '重大', '《中华人民共和国安全生产法》', '第五十一条', '生产经营单位必须依法参加工伤保险，为从业人员缴纳保险费。国家鼓励生产经营单位投保安全生产责任保险。'),
(1891, 20, '药品生产压缩空气系统故障', '药品生产压缩空气系统故障隐患排查', '较大', '《中华人民共和国安全生产法》', '第七十八条', '生产经营单位应当制定本单位生产安全事故应急救援预案，与所在地县级以上地方人民政府组织制定的生产安全事故应急救援预案相衔接，并定期组织演练。'),
(1892, 20, '药品生产洁净区压差异常', '药品生产洁净区压差异常隐患排查', '一般', '《中华人民共和国安全生产法》', '第八十一条', '生产经营单位应当建立安全风险分级管控制度，按照安全风险分级采取相应的管控措施。生产经营单位应当建立健全生产安全事故隐患排查治理制度，采取技术、管理措施，及时发现并消除事故隐患。'),
